INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-06-18', 'மேற்கோள்', 'எடுத்துக்காட்டு, Quotation', 'திருக்குறளை மேற்கோள் காட்டினார்.');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-06-19', 'கண்கூடு', 'வெளிப்படை, கண்களுக்கு எளிதில் புலப்படும் உண்மை, obvious', 'சுற்றுச்சூழலை பாத்துக்க மரம் வளர்த்தல் எவ்வளவு கட்டாயம் என்பது கண்கூடு');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-06-20', 'முதன்மை', 'தலைமை, primary, supreme', 'முதன்மை செயலாளர்');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-06-21', 'பயணம்', 'வழிப்போக்கு, வழிச்செலவு, travel, journey', 'தொடர்வண்டி பயணம் எளிதாக இருந்தது');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-06-22', 'முறையீடு', 'குறை தீர்க்கக் விண்ணப்பம் விடுதல், complaint, petition', 'குடிநீர் பற்றாக்குறையை தீர்க்க ஆட்சியரிடம் முறையீடு செய்யப்பட்டது');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-06-23', 'வளர்பிறை', 'அமாவாசைக்கு பிறகு நிலவு வளரும் பருவம், waxing moon', 'வளர்பிறையில் நிலவு வலதுபுறமும் (Ɔ வடிவில் ), தேய்பிறையில் இடதுபுறமும் (C வடிவில்) இருக்கும்');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-06-24', 'சோம்பல்', 'செயல்படாமல் ஆர்வமின்றி ஓய்வில் திளைத்திருத்தல், laziness', 'முடிக்கவேண்டியதை பிறகு பார்த்துக்கொள்வோம் என தள்ளிபோடுபவன் சோம்பேறி');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-06-25', 'பதாகை', 'அடையாளக் கொடி, சின்னம், banner', 'வழியெங்கும் அரசியல் கட்சியின் பதாகைகள் காணப்படுகிறது.<br/><br/>அரசருக்கு முன் அரச பதாகையை ஏந்தி வந்தனர்.');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-06-26', 'குவியம்', 'பார்வை குவியும் புள்ளி, focus, focal point', 'குவியம் சரியாக இருந்தால் தான் பிம்பம் நன்றாக இருக்கும்');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-06-27', 'பகட்டு', 'மினுக்கம், ஆடம்பரம், extravagance, foppery, luxuary', 'அவர் தன் மகளுக்கு பகட்டான திருமணம் நடத்தினார்');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-06-28', 'தெகிடி', 'சூது விளையாட்டுவகை, புரட்டு, gambling, fraud, deception', 'கைகூடுவது போல் தோன்றி ஏமாற்றும் தெகிடி');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-06-29', 'ஊற்று', 'நீரூற்று, நீர் சுரத்தல், spring, fountain', 'நேற்று மழை பெய்ததால் கிணறுகளில் ஊற்று எடுத்துள்ளது');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-06-30', 'சுடர்', 'ஒளிக்கதிர், கொழுந்து, flame', 'தீ சுடர் விட்டு எரிந்தது');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-01', 'தெளிவு', 'விளக்கம், சான்று, clarity, clear truth, clear vision', 'திருக்குறளுக்கு தெளிவுரை எழுதினார்<br/><br/>தெளிவாக தெரிந்தது<br/><br/>நீரின்றி அமையாது உலகு என்பது தெளிவு');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-02', 'ஆழம்', 'மேலிருந்து கீழான அளவு, depth', 'ஆழம் தெரியாமல் காலை விடாதே');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-03', 'சலிப்பு', 'வெறுப்பு, சோர்வு, boredom, weariness', 'எத்தனை முறை கேட்டாலும் சலிக்காத பாடல்<br/><br/>ஒரே மாதிரியான வேலை எனக்குச் சலிப்புத் தருகிறது');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-04', 'வல்லூறு', 'கழுகு இனங்களில் ஒரு இனம், வைரி, falcon', 'மேய்ந்துக் கொண்டிருந்தக் கோழிக்குஞ்சை வல்லூறு பிடித்துச் சென்றது.');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-05', 'காட்சி', 'பார்வை, காணல், தோற்றம், sight, vision, scene', 'குரங்குகள் சண்டையிடும் காட்சியை எல்லோரும் வேடிக்கை பார்த்துக்கொண்டு இருந்தனர்<br/><br/>தொலைக்காட்சி, கண்காட்சி');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-06', 'ஆவல்', 'விருப்பம், ஆர்வம், desire, wish, craving', 'நலம், நலமறிய ஆவல்.');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-07', 'சாயல்', 'ஒன்றைப் போன்று ஒத்திருத்தல், likeness, similarity', 'குழந்தை அதன் அம்மா சாயலில் உள்ளது');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-08', 'இத்யாதி', 'இன்னபிற, etcetera; and the rest', 'இத்யாதி காதல் இல்லாத போதும் தேடும் தேடல்(திரைப்பட பாடல்)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-09', 'ஊடல்', 'உறவுகளுக்குள் கருத்து வேறுபாட்டால் வரும் (சிறிய) பிணக்கு, பொய்க்கோபம்', 'கணவன் மனைவியிடையே ஒரு சிறிய ஊடல்');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-10', 'கண்ணீர்', 'கண்ணில் வழியும் நீர், tears', 'அழுது கண்ணீர் வடித்தான்');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-11', 'ஊஞ்சல்', 'ஊசல், swing', 'அவள் ஊஞ்சல் ஆடினாள்');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-12', 'புலரி', 'விடியல், வைகறை, சூரியன், தோன்றும் காலைப்பொழுது, சூரியன், dawn, sun', 'புலராத காலைதனிலே(திரைப்பட பாடல்)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-13', 'அந்தாதி', 'ஒரு பாடல் முடிவில் உள்ள எழுத்து, அசை, சீர், சொல் அல்லது அடி அடுத்து வரும் பாடலின் தொடக்கமாக அமையும் பாடல்களால் ஆன செய்யுள்/பிரபந்தம்; முதலும் முடிவும்', 'அந்தாதி பாடல் எழுதினான்');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-14', 'மாற்றம்', 'ஒன்றிலிருந்து, மற்றொரு நிலைக்கு மாறுவது, change', 'ஓர் ஆண்டில் இந்த பகுதி நிறைய மாற்றம் பெற்றுள்ளது');
