INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-21', 'தோழமை', 'நட்பு, friendship, companionship', 'சமூகத்தில் எல்லோரும் தோழமையுடன் பழக வேண்டும்.');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-07-22', 'முடிவிலி', 'முடிவு இல்லாதது, infinity, eternity', 'கணிதத்தில் முடிவில்லாத எண்ணை குறிக்கும் சொல் முடிவிலி.');
