INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-12-11', 'பாட்டை', NULL, NULL);
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2023-12-12', 'கற்பனை', NULL, NULL);
