INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-06-02', 'கட்டளை', 'ஆணை, கட்டுப்பாடு, command, order', 'அங்கேயே நில் என்று கட்டளை இட்டார்.');
