INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-14', 'மேற்கோள்', 'எடுத்துக்காட்டு, Quotation', 'திருக்குறளை மேற்கோள் காட்டினார்.');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-15', 'கண்கூடு', 'வெளிப்படை, கண்களுக்கு எளிதில் புலப்படும் உண்மை, obvious', 'சுற்றுச்சூழலை பாத்துக்க மரம் வளர்த்தல் எவ்வளவு கட்டாயம் என்பது கண்கூடு');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-16', 'முதன்மை', 'தலைமை, primary, supreme', 'முதன்மை செயலாளர்');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-17', 'பயணம்', 'வழிப்போக்கு, வழிச்செலவு, travel, journey', 'தொடர்வண்டி பயணம் எளிதாக இருந்தது');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-18', 'முறையீடு', 'குறை தீர்க்கக் விண்ணப்பம் விடுதல், complaint, petition', 'குடிநீர் பற்றாக்குறையை தீர்க்க ஆட்சியரிடம் முறையீடு செய்யப்பட்டது');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-19', 'வளர்பிறை', 'அமாவாசைக்கு பிறகு நிலவு வளரும் பருவம், waxing moon', 'வளர்பிறையில் நிலவு வலதுபுறமும் (Ɔ வடிவில் ), தேய்பிறையில் இடதுபுறமும் (C வடிவில்) இருக்கும்');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-20', 'சோம்பல்', 'செயல்படாமல் ஆர்வமின்றி ஓய்வில் திளைத்திருத்தல், laziness', 'முடிக்கவேண்டியதை பிறகு பார்த்துக்கொள்வோம் என தள்ளிபோடுபவன் சோம்பேறி');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-21', 'பதாகை', 'அடையாளக் கொடி, சின்னம், banner', 'வழியெங்கும் அரசியல் கட்சியின் பதாகைகள் காணப்படுகிறது.<br/><br/>அரசருக்கு முன் அரச பதாகையை ஏந்தி வந்தனர்.');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-22', 'குவியம்', 'பார்வை குவியும் புள்ளி, focus, focal point', 'குவியம் சரியாக இருந்தால் தான் பிம்பம் நன்றாக இருக்கும்');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-23', 'பகட்டு', 'மினுக்கம், ஆடம்பரம், extravagance, foppery, luxuary', 'அவர் தன் மகளுக்கு பகட்டான திருமணம் நடத்தினார்');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-24', 'தெகிடி', 'சூது விளையாட்டுவகை, புரட்டு, gambling, fraud, deception', 'கைகூடுவது போல் தோன்றி ஏமாற்றும் தெகிடி');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-25', 'ஊற்று', 'நீரூற்று, நீர் சுரத்தல், spring, fountain', 'நேற்று மழை பெய்ததால் கிணறுகளில் ஊற்று எடுத்துள்ளது');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-26', 'சுடர்', 'ஒளிக்கதிர், கொழுந்து, flame', 'தீ சுடர் விட்டு எரிந்தது');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-27', 'தெளிவு', 'விளக்கம், சான்று, clarity, clear truth, clear vision', 'திருக்குறளுக்கு தெளிவுரை எழுதினார்<br/><br/>தெளிவாக தெரிந்தது<br/><br/>நீரின்றி அமையாது உலகு என்பது தெளிவு');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-28', 'ஆழம்', 'மேலிருந்து கீழான அளவு, depth', 'ஆழம் தெரியாமல் காலை விடாதே');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-29', 'சலிப்பு', 'வெறுப்பு, சோர்வு, boredom, weariness', 'எத்தனை முறை கேட்டாலும் சலிக்காத பாடல்<br/><br/>ஒரே மாதிரியான வேலை எனக்குச் சலிப்புத் தருகிறது');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-30', 'வல்லூறு', 'கழுகு இனங்களில் ஒரு இனம், வைரி, falcon', 'மேய்ந்துக் கொண்டிருந்தக் கோழிக்குஞ்சை வல்லூறு பிடித்துச் சென்றது.');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2025-12-31', 'காட்சி', 'பார்வை, காணல், தோற்றம், sight, vision, scene', 'குரங்குகள் சண்டையிடும் காட்சியை எல்லோரும் வேடிக்கை பார்த்துக்கொண்டு இருந்தனர்<br/><br/>தொலைக்காட்சி, கண்காட்சி');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2026-01-01', 'ஆவல்', 'விருப்பம், ஆர்வம், desire, wish, craving', 'நலம், நலமறிய ஆவல்.');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2026-01-02', 'சாயல்', 'ஒன்றைப் போன்று ஒத்திருத்தல், likeness, similarity', 'குழந்தை அதன் அம்மா சாயலில் உள்ளது');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2026-01-03', 'இத்யாதி', 'இன்னபிற, etcetera; and the rest', 'இத்யாதி காதல் இல்லாத போதும் தேடும் தேடல்(திரைப்பட பாடல்)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2026-01-04', 'ஊடல்', 'உறவுகளுக்குள் கருத்து வேறுபாட்டால் வரும் (சிறிய) பிணக்கு, பொய்க்கோபம்', 'கணவன் மனைவியிடையே ஒரு சிறிய ஊடல்');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2026-01-05', 'கண்ணீர்', 'கண்ணில் வழியும் நீர், tears', 'அழுது கண்ணீர் வடித்தான்');
