INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2026-01-07', 'புலரி', 'விடியல், வைகறை, சூரியன், தோன்றும் காலைப்பொழுது, சூரியன், dawn, sun', 'புலராத காலைதனிலே(திரைப்பட பாடல்)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2026-01-08', 'அந்தாதி', 'ஒரு பாடல் முடிவில் உள்ள எழுத்து, அசை, சீர், சொல் அல்லது அடி அடுத்து வரும் பாடலின் தொடக்கமாக அமையும் பாடல்களால் ஆன செய்யுள்/பிரபந்தம்; முதலும் முடிவும்', 'அந்தாதி பாடல் எழுதினான்');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2026-01-09', 'மாற்றம்', 'ஒன்றிலிருந்து, மற்றொரு நிலைக்கு மாறுவது, change', 'ஓர் ஆண்டில் இந்த பகுதி நிறைய மாற்றம் பெற்றுள்ளது');
