INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2026-01-11', 'சூழல்', 'நம்மை சுற்றி இருக்கும் இடம்/ சுற்றி நிகழும் நிகழ்வு, surrounding, situation, environment', 'இதை செய்வதற்கு நல்ல சூழல் அமைந்துள்ளது');
