INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('normal', '2026-01-16', 'தோழமை', 'நட்பு, friendship, companionship', 'சமூகத்தில் எல்லோரும் தோழமையுடன் பழக வேண்டும்.');
