INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-05-30', 'நாப்பண்', 'நடு, நடுவில், middle, center', 'பன்மீன் <strong>நாப்பண்</strong> திங்கள் போலவும் (புறம்–13)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-05-31', 'மரியவர்', 'பின்பற்றி நடப்பவர், adherents, followers', '<strong>மரீஇயோர்</strong> அறியாது மைந்துபட் டன்றே (புறம்–13)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-01', 'அழுவம்', 'பரப்பு, ஆழம், surface, depth', 'நீர் <strong>அழுவம்</strong> நிவப்புக் குறித்து (புறம்–14)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-02', 'பரிதல்', 'ஓடுதல், to run', 'நிமிர் <strong>பரிய</strong> மா தாங்கவும் (புறம்–14)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-03', 'குரிசில்', 'தலைவன், lord, chief', 'பரிசிலர்க்கு அருங்கலம் நல்கவும், <strong>குரிசில்</strong>! (புறம்–14)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-04', 'பொருநர்', 'போர்வீரர், பகைவர், soldier', '<strong>பொருநர்க்கு</strong> இருநிலத்து அன்ன நோன்மை (புறம்–14)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-05', 'ஞெள்ளல்', 'தெரு, street', 'கடுந்தேர் குழித்த <strong>ஞெள்ளல்</strong> ஆங்கண் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-06', 'நனம்', 'அகற்சி, அகலம், wide, extent', 'பாழ்செய் தனை, அவர் <strong>நனந்தலை</strong> நல்லெயில் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-07', 'புள்ளினம்', 'பறவையினம், flock of birds', '<strong>புள்ளினம்</strong> இமிழும் புகழ்சால் விளைவயல் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-08', 'இமிழ்', 'முழங்கு, ஒலி எழுப்பு, blowing music, sweet loud roar', 'புள்ளினம் <strong>இமிழும்</strong> புகழ்சால் விளைவயல் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-09', 'உகளல்', 'தாவுதல், to leap', 'கவிகுளம்பு <strong>உகள</strong>(புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-10', 'கலிமான்', 'குதிரை, horse', 'வெள்ளுளைக் <strong>கலிமான்</strong> (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-11', 'தெவ்வர்', 'பகைவர், enemy', '<strong>தெவ்வர்</strong> தேஎத்து (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-12', 'எருத்து', 'கழுத்து, neck', 'பணை <strong>எருத்தின்</strong> பா வடியாற் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-13', 'செறல்', 'கோபம், anger', '<strong>செறல்</strong> நோக்கின் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-14', 'மருப்பு', 'விலங்கின் கொம்பு, யானைக்கொம்பு, horn, tusk', 'ஒளிறு <strong>மருப்பின்</strong> களிறு (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-15', 'பிறக்கு', 'பின்பு, later', 'நசைதர வந்தோர் நசை<strong>பிறக்கு</strong> ஒழிய (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-16', 'கண்ணுறை', 'மேலே தூவுவது, மசாலா, கறி', 'பெருங்<strong>கண்ணுறை</strong> நெய்ம் மலி ஆவுதி பொங்க (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-17', 'மண்கனை', 'ஒருவகை முழவு, a Drum', '<strong>மண்கனை</strong> முழவின் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-18', 'மைந்து', 'பிள்ளை, வலிமை, child, strength', 'சான்ற <strong>மைந்தினோய்</strong>(புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-19', 'முழவு', 'முரசு, பறை, a drum', 'மண்கனை <strong>முழவின்</strong>(புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-20', 'செக்கர்', 'மாலையில் கதிரவன் மறையும் பொழுது சிவந்து இருக்கும் வானம், செவ்வானம், a red sky at dawn or sunset', 'ஞாயிற்றுச் <strong>செக்கரின்</strong>தோன்ற (புறம்–16)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-21', 'வள்ளை', 'ஒருகொடி, creeping bindweed', 'மயங்கு <strong>வள்ளை</strong> மலர்ஆம்பல் (புறம்–16)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-22', 'கானல்', 'பாலைவனம், மணல்,  desert or any arid place, sand', 'நிலவு மணல் வியன் <strong>கானல்</strong> (புறம்–17)');
