INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-06-28', 'உம்பல்', 'வழித்தோன்றல்', 'ஒருதாம் ஆகிய உரவோர் <strong>உம்பல்!</strong> (புறம்–18)');
