INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-11-17', 'நாப்பண்', 'நடு, நடுவில், middle, center', 'பன்மீன் <strong>நாப்பண்</strong> திங்கள் போலவும் (புறம்–13)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-11-18', 'மரியவர்', 'பின்பற்றி நடப்பவர், adherents, followers', '<strong>மரீஇயோர்</strong> அறியாது மைந்துபட் டன்றே (புறம்–13)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-11-19', 'அழுவம்', 'பரப்பு, ஆழம், surface, depth', 'நீர் <strong>அழுவம்</strong> நிவப்புக் குறித்து (புறம்–14)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-11-20', 'பரிதல்', 'ஓடுதல், to run', 'நிமிர் <strong>பரிய</strong> மா தாங்கவும் (புறம்–14)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-11-21', 'குரிசில்', 'தலைவன், lord, chief', 'பரிசிலர்க்கு அருங்கலம் நல்கவும், <strong>குரிசில்</strong>! (புறம்–14)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-11-22', 'பொருநர்', 'போர்வீரர், பகைவர், soldier', '<strong>பொருநர்க்கு</strong> இருநிலத்து அன்ன நோன்மை (புறம்–14)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-11-23', 'ஞெள்ளல்', 'தெரு, street', 'கடுந்தேர் குழித்த <strong>ஞெள்ளல்</strong> ஆங்கண் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-11-24', 'நனம்', 'அகற்சி, அகலம், wide, extent', 'பாழ்செய் தனை, அவர் <strong>நனந்தலை</strong> நல்லெயில் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-11-25', 'புள்ளினம்', 'பறவையினம், flock of birds', '<strong>புள்ளினம்</strong> இமிழும் புகழ்சால் விளைவயல் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-11-26', 'இமிழ்', 'முழங்கு, ஒலி எழுப்பு, blowing music, sweet loud roar', 'புள்ளினம் <strong>இமிழும்</strong> புகழ்சால் விளைவயல் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-11-27', 'உகளல்', 'தாவுதல், to leap', 'கவிகுளம்பு <strong>உகள</strong>(புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-11-28', 'கலிமான்', 'குதிரை, horse', 'வெள்ளுளைக் <strong>கலிமான்</strong> (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-11-29', 'தெவ்வர்', 'பகைவர், enemy', '<strong>தெவ்வர்</strong> தேஎத்து (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-11-30', 'எருத்து', 'கழுத்து, neck', 'பணை <strong>எருத்தின்</strong> பா வடியாற் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-01', 'செறல்', 'கோபம், anger', '<strong>செறல்</strong> நோக்கின் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-02', 'மருப்பு', 'விலங்கின் கொம்பு, யானைக்கொம்பு, horn, tusk', 'ஒளிறு <strong>மருப்பின்</strong> களிறு (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-03', 'பிறக்கு', 'பின்பு, later', 'நசைதர வந்தோர் நசை<strong>பிறக்கு</strong> ஒழிய (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-04', 'கண்ணுறை', 'மேலே தூவுவது, மசாலா, கறி', 'பெருங்<strong>கண்ணுறை</strong> நெய்ம் மலி ஆவுதி பொங்க (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-05', 'மண்கனை', 'ஒருவகை முழவு, a Drum', '<strong>மண்கனை</strong> முழவின் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-06', 'மைந்து', 'பிள்ளை, வலிமை, child, strength', 'சான்ற <strong>மைந்தினோய்</strong>(புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-07', 'முழவு', 'முரசு, பறை, a drum', 'மண்கனை <strong>முழவின்</strong>(புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-08', 'செக்கர்', 'மாலையில் கதிரவன் மறையும் பொழுது சிவந்து இருக்கும் வானம், செவ்வானம், a red sky at dawn or sunset', 'ஞாயிற்றுச் <strong>செக்கரின்</strong>தோன்ற (புறம்–16)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-09', 'வள்ளை', 'ஒருகொடி, creeping bindweed', 'மயங்கு <strong>வள்ளை</strong> மலர்ஆம்பல் (புறம்–16)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-10', 'கானல்', 'பாலைவனம், மணல்,  desert or any arid place, sand', 'நிலவு மணல் வியன் <strong>கானல்</strong> (புறம்–17)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-11', 'பயம்பு', 'பள்ளம், pit', 'மாப் <strong>பயம்பின்</strong> பொறை (புறம்–17)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-12', 'ஏந்தல்', 'தேக்கம், உயர்ச்சி, pool, height', '<strong>ஏந்து</strong> கொடி இறைப் புரிசை (புறம்–17)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-13', 'புரிசை', 'மதில்', 'ஏந்து கொடி இறைப் <strong>புரிசை</strong> (புறம்–17)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-14', 'அருப்பம்', 'அரண், மதில், அருமை', 'வீங்கு சிறை வியல் <strong>அருப்பம்</strong> (புறம்–17)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-15', 'ஈண்டுதல்', 'திரளுதல், கூடுதல்', '<strong>ஈண்டிய</strong> மழையென மருளும் (புறம்–17)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-16', 'உம்பல்', 'வழித்தோன்றல்', 'ஒருதாம் ஆகிய உரவோர் <strong>உம்பல்!</strong> (புறம்–18)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-17', 'கெடிறு', 'கெளிற்று மீன்', 'குரூஉக் <strong>கெடிற்ற</strong>, குண்டு அகழி; (புறம்–18)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-18', 'மல்லல்', 'வளமை', '<strong>மல்லல்</strong> மூதூர் வய வேந்தே! (புறம்–18)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-19', 'வல்லே', 'விரைவாக', 'அடுபோர்ச் செழிய! இகழாது <strong>வல்லே</strong> (புறம்–18)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-20', 'அடார்', 'விலங்குளை அகப்பபடுத்தும் பொறி', 'பெருங்கல் <strong>அடாரும்</strong> போன்ம்என விரும்பி (புறம்–19)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2023-12-21', 'போன்ம்', 'போலும்', 'பெருங்கல் அடாரும் <strong>போன்ம்</strong>என விரும்பி (புறம்–19)');
