INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-10-24', 'நாப்பண்', 'நடு, நடுவில், middle, center', 'பன்மீன் <strong>நாப்பண்</strong> திங்கள் போலவும் (புறம்–13)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-10-25', 'மரியவர்', 'பின்பற்றி நடப்பவர், adherents, followers', '<strong>மரீஇயோர்</strong> அறியாது மைந்துபட் டன்றே (புறம்–13)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-10-26', 'அழுவம்', 'பரப்பு, ஆழம், surface, depth', 'நீர் <strong>அழுவம்</strong> நிவப்புக் குறித்து (புறம்–14)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-10-27', 'பரிதல்', 'ஓடுதல், to run', 'நிமிர் <strong>பரிய</strong> மா தாங்கவும் (புறம்–14)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-10-28', 'குரிசில்', 'தலைவன், lord, chief', 'பரிசிலர்க்கு அருங்கலம் நல்கவும், <strong>குரிசில்</strong>! (புறம்–14)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-10-29', 'பொருநர்', 'போர்வீரர், பகைவர், soldier', '<strong>பொருநர்க்கு</strong> இருநிலத்து அன்ன நோன்மை (புறம்–14)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-10-30', 'ஞெள்ளல்', 'தெரு, street', 'கடுந்தேர் குழித்த <strong>ஞெள்ளல்</strong> ஆங்கண் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-10-31', 'நனம்', 'அகற்சி, அகலம், wide, extent', 'பாழ்செய் தனை, அவர் <strong>நனந்தலை</strong> நல்லெயில் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-01', 'புள்ளினம்', 'பறவையினம், flock of birds', '<strong>புள்ளினம்</strong> இமிழும் புகழ்சால் விளைவயல் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-02', 'இமிழ்', 'முழங்கு, ஒலி எழுப்பு, blowing music, sweet loud roar', 'புள்ளினம் <strong>இமிழும்</strong> புகழ்சால் விளைவயல் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-03', 'உகளல்', 'தாவுதல், to leap', 'கவிகுளம்பு <strong>உகள</strong>(புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-04', 'கலிமான்', 'குதிரை, horse', 'வெள்ளுளைக் <strong>கலிமான்</strong> (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-05', 'தெவ்வர்', 'பகைவர், enemy', '<strong>தெவ்வர்</strong> தேஎத்து (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-06', 'எருத்து', 'கழுத்து, neck', 'பணை <strong>எருத்தின்</strong> பா வடியாற் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-07', 'செறல்', 'கோபம், anger', '<strong>செறல்</strong> நோக்கின் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-08', 'மருப்பு', 'விலங்கின் கொம்பு, யானைக்கொம்பு, horn, tusk', 'ஒளிறு <strong>மருப்பின்</strong> களிறு (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-09', 'பிறக்கு', 'பின்பு, later', 'நசைதர வந்தோர் நசை<strong>பிறக்கு</strong> ஒழிய (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-10', 'கண்ணுறை', 'மேலே தூவுவது, மசாலா, கறி', 'பெருங்<strong>கண்ணுறை</strong> நெய்ம் மலி ஆவுதி பொங்க (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-11', 'மண்கனை', 'ஒருவகை முழவு, a Drum', '<strong>மண்கனை</strong> முழவின் (புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-12', 'மைந்து', 'பிள்ளை, வலிமை, child, strength', 'சான்ற <strong>மைந்தினோய்</strong>(புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-13', 'முழவு', 'முரசு, பறை, a drum', 'மண்கனை <strong>முழவின்</strong>(புறம்–15)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-14', 'செக்கர்', 'மாலையில் கதிரவன் மறையும் பொழுது சிவந்து இருக்கும் வானம், செவ்வானம், a red sky at dawn or sunset', 'ஞாயிற்றுச் <strong>செக்கரின்</strong>தோன்ற (புறம்–16)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-15', 'வள்ளை', 'ஒருகொடி, creeping bindweed', 'மயங்கு <strong>வள்ளை</strong> மலர்ஆம்பல் (புறம்–16)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-16', 'கானல்', 'பாலைவனம், மணல்,  desert or any arid place, sand', 'நிலவு மணல் வியன் <strong>கானல்</strong> (புறம்–17)');
