INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-18', 'ஏந்தல்', 'தேக்கம், உயர்ச்சி, pool, height', '<strong>ஏந்து</strong> கொடி இறைப் புரிசை (புறம்–17)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-19', 'புரிசை', 'மதில்', 'ஏந்து கொடி இறைப் <strong>புரிசை</strong> (புறம்–17)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-20', 'அருப்பம்', 'அரண், மதில், அருமை', 'வீங்கு சிறை வியல் <strong>அருப்பம்</strong> (புறம்–17)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-21', 'ஈண்டுதல்', 'திரளுதல், கூடுதல்', '<strong>ஈண்டிய</strong> மழையென மருளும் (புறம்–17)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-22', 'உம்பல்', 'வழித்தோன்றல்', 'ஒருதாம் ஆகிய உரவோர் <strong>உம்பல்!</strong> (புறம்–18)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-23', 'கெடிறு', 'கெளிற்று மீன்', 'குரூஉக் <strong>கெடிற்ற</strong>, குண்டு அகழி; (புறம்–18)');
INSERT INTO words (mode, date, word, meaning, usage_html) VALUES ('sentamil', '2024-11-24', 'மல்லல்', 'வளமை', '<strong>மல்லல்</strong> மூதூர் வய வேந்தே! (புறம்–18)');
